var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"샤레이드 산업 지구, <color=#ffd34c>본선 리그 개최 중</color>","JPN":"シャレード産業地区、<color=#ffd34c>本戦リーグ開催中</color>","ENG":"Charade Industrial District, <color=#ffd34c>Gauntlet elimination rounds ongoing</color>","TWN":"查雷德工業區，<color=#ffd34c>正在舉辦聯賽</color>","SCN":"查雷德工业区，<color=#ffd34c>正在举办本赛联赛</color>","DEU":"Charade Industrial District, <color=#ffd34c>Gauntlet elimination rounds ongoing</color>","FRA":"Charade Industrial District, <color=#ffd34c>Gauntlet elimination rounds ongoing</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"괜찮으신가요, 부단장님? 아까부터 조금도 움직이지 않고 계십니다.","JPN":"大丈夫ですか、副団長？　さっきからまったく動いていませんが。","ENG":"Are you all right, Deputy? You haven't moved a muscle for a while.","TWN":"你還好嗎，副團長？從剛才開始就一直沒有動靜。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"정신을 집중하기 위해 잠시 명상 중이었습다만.","JPN":"精神を集中するために瞑想していました。","ENG":"I was meditating to focus my mind.","TWN":"為了集中精神，我剛才在冥想。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"책임을 지는 자리라는 건, 무겁군요. 단장님도 항상 이런 중압감에 시달리셨겠죠.","JPN":"責任を伴う座というのは、重いですね。団長もいつもこんなプレッシャーを感じていたのでしょう。","ENG":"The burden of responsibility... is heavy. I suppose Captain always bore this kind of pressure too.","TWN":"承擔責任的位置，果然沉重。團長你也一直被這種壓力所困擾吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"원로 할아버지들 말은 신경 쓰지 마. 단장도 소녀니까 바람 쐬고 싶은 날이 있는 거겠지.","JPN":"元老のジジイたちのことは気にしないで。団長だって女の子なんだし、ちょっと風に当たりたい時があるんだよ。","ENG":"Forget what those old fogies said. Captain's a girl too, she's allowed to take a break when she needs one.","TWN":"別在意那些元老爺爺的話。團長也是少女，有時候也想出去透透氣吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YANGHANSOL_ZODIAC_NULL_NULL","text":{"KOREA":"예. 저희가 굳건히 자리를 지키면 단장님께서도 안심하고 돌아오실 수 있을 겁니다.","JPN":"そうです。私たちが持ち場を守り続けていれば、団長も安心して帰って来られるはずです。","ENG":"Yes. If we stand our ground, she'll be able to return without worry.","TWN":"是的。如果我們堅守崗位，團長也能安心回來。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YANGHANSOL_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……두 분 말이 맞습니다. 지금은 멋대로 사색에 잠길 때가 아니죠.","JPN":"……おっしゃる通りです。今は思いにふけっている場合ではありませんでした。","ENG":"...You're both right. Now's not the time to get lost in thought.","TWN":"……兩位說得對。現在不是隨意沉思的時候。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다른 기사분들이 지켜볼지도 모르는 경기를 부끄러운 마음으로 임할 뻔했습니다.","JPN":"他の騎士の方々も見ているかもしれない試合に、危うく恥ずかしい気持ちで挑むところでした。","ENG":"I nearly stepped into the match with a clouded heart. What a shame that would've been.","TWN":"差點以羞愧的心情參加了其他騎士們可能會觀看的比賽。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"각오는 끝마쳤습니다. 모두, 가죠.","JPN":"覚悟はできています。さあ、行きましょう。","ENG":"I'm ready now. Everyone, let's go.","TWN":"已經做好準備了。大家，出發吧。"},"stage":{"bg":"OFFICE_LOCKERROOM","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"카나리아 스쿼드의 팀 엔트리 변경이라는 강수! 하지만~? 상대는 유구한 역사를 지닌 태스크포스다!","JPN":"カナリア・スクワッド、エントリー変更という大胆な勝負手！　しかし～？　相手は長い歴史を誇るタスクフォースだ！","ENG":"A bold move from Canary Squad changing their roster! But! Their opponent is a TASKFORCE with a long and proud history!","TWN":"金絲雀小隊的隊員變動是個大膽的舉動！但是～？對手可是擁有悠久歷史的特遣勢力啊！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"자! 다음으로! 공격팀은……!","JPN":"さて！　次に！　攻撃チームは……！","ENG":"And now! For the attacking team...!","TWN":"好的！接下來！進攻方是……！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■ ■</color> 어?? 얘네 그거 아니야?\\n<color=#ffd34c>■ ■</color> 설마 얘네가 나온다고ㅋㅋㅋㅋ?\\n<color=#ffd34c>■ ■</color> 얘네 클리포트 게임 때문에 한참 말 많은 애들이잖아!","JPN":"<color=#ffd34c>■ ■</color> あ？？　あいつら、アレじゃない？\\n<color=#ffd34c>■ ■</color> まさかこいつらが出るなんてｗｗｗｗ\\n<color=#ffd34c>■ ■</color> こいつら、クリフォトゲームで話題になってんじゃん！","ENG":"<color=#ffd34c>■ ■</color> Huh?? I know them!\\n<color=#ffd34c>■ ■</color> They're competing too? HAHAHA!\\n<color=#ffd34c>■ ■</color> They're the ones from the Qliphoth Game!","TWN":"<color=#ffd34c>■ ■</color> 哎?? 他們不是那個嗎?\\n<color=#ffd34c>■ ■</color> 不會吧，他們居然出現了哈哈哈?\\n<color=#ffd34c>■ ■</color> 他們就是因為逆卡巴拉遊戲而被議論紛紛的那些傢伙!","SCN":"<color=#ffd34c>■ ■</color> 哎?? 他们不是那个吗?\\n<color=#ffd34c>■ ■</color> 不会吧，他们居然出现了哈哈哈?\\n<color=#ffd34c>■ ■</color> 他们就是因为神圣战役而被议论纷纷的那些家伙!","DEU":"<color=#ffd34c>■ ■</color> Huh?? I know them!\\n<color=#ffd34c>■ ■</color> They're competing too? HAHAHA!\\n<color=#ffd34c>■ ■</color> They're the ones from the Qliphoth Game!","FRA":"<color=#ffd34c>■ ■</color> Huh?? I know them!\\n<color=#ffd34c>■ ■</color> They're competing too? HAHAHA!\\n<color=#ffd34c>■ ■</color> They're the ones from the Qliphoth Game!"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"맞아! 맞아!","JPN":"そう！　そうなんだよ！","ENG":"Yes! You're right!","TWN":"沒錯！沒錯！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"다들 넷튜브에 뜬 클리포트 게임 생중계 영상은 봤지?","JPN":"みんな、ネットチューブにアップされたクリフォトゲームの生中継見たよね？","ENG":"You've all seen the live feed of the Qliphoth Game on NetTube, right?","TWN":"大家都有在網路上看過逆卡巴拉遊戲的直播影片吧？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>■■■</color> 클리포트 게임이 뭐임? 나 진짜 모름ㅋㅋㅋㅋㅋ\\n<color=#ffd34c>■■■</color> 새로 나온 모바일 게임임?","JPN":"<color=#ffd34c>■■■</color> クリフォトゲームって何？　マジ初耳ｗｗｗｗｗ\\n<color=#ffd34c>■■■</color> 新しく発売されたモバゲー？","ENG":"<color=#ffd34c>■■■</color> What's the Qliphoth Game? I really don't know. LMAO!\\n<color=#ffd34c>■■■</color> Is it some new mobile game?","TWN":"<color=#ffd34c>■■■</color> 逆卡巴拉遊戲是什麼？我真的不知道哈哈哈哈\\n<color=#ffd34c>■■■</color> 是新出的手機遊戲嗎？","SCN":"<color=#ffd34c>■■■</color> 神圣战役是什么？我真的不知道哈哈哈哈\\n<color=#ffd34c>■■■</color> 是新出的手机游戏吗？","DEU":"<color=#ffd34c>■■■</color> What's the Qliphoth Game? I really don't know. LMAO!\\n<color=#ffd34c>■■■</color> Is it some new mobile game?","FRA":"<color=#ffd34c>■■■</color> What's the Qliphoth Game? I really don't know. LMAO!\\n<color=#ffd34c>■■■</color> Is it some new mobile game?"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"뭐어─? 안 봤다구? 대 충격! 여태껏 안 보고 뭐했어!","JPN":"はあ～？　見てないの？　大ショック！　今まで何してたの！？","ENG":"Whaaaaaaaat? You didn't watch it? Shocker! What were you doing instead of watching it?","TWN":"什麼─？沒看過？不敢相信！竟然到現在都還沒看過！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"안 본 애들은 당장 넷튜브 가서 보고 와!","JPN":"見てない人は、今すぐネットチューブで見てこーい！","ENG":"If you haven't seen it, go to NetTube and watch it right now!","TWN":"沒看過的人現在就給我去看，看完再回來！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"왜 그 있잖아! 이면세계에서 태스크포스랑 칼 들고 덤비는 침식체들이랑 한판 붙었던 그거!","JPN":"ほら、アレだよ！　裏世界でタスクフォースと剣持って飛びかかる侵食体とが戦ってた、アレ！","ENG":"Didn't you watch that? The TASKFORCEs fought those sword-wielding C.O.s in Counterside!","TWN":"就是那個啊！在異界和特遣勢力一起拔刀對抗侵蝕體的影片！"},"stage":{"bg":"MS_1104","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이 밋치미치도 진짜 숨죽이면서 봤다니까!","JPN":"このミッチーミッチーも、本当に固唾を呑んで見守ったんだから！","ENG":"I was on the edge of my seat watching it!","TWN":"米琪我也是看得膽戰心驚的呢！"},"stage":{"bg":"MS_1104","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그런데 대박 사건!! 다들 그거 알고 있었어?","JPN":"でも、大事件！！　みんな、これ知ってた？","ENG":"But lo and behold!! Did you guys know this?","TWN":"不過還有更驚人的！大家知道嗎？"},"stage":{"bg":"MS_1104","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"관리국의 정식 라이선스를 발급받은 태스크포스 중에는…….","JPN":"管理局の正式ライセンスを持っているタスクフォースの中には……","ENG":"Among the TASKFORCEs that have received their official license from the Administration...","TWN":"管理局有發給正式執照的特遣勢力中……"},"stage":{"bg":"MS_1104","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"그 기사 침식체들을 흉내 내고 다니는 녀석들이 있었다는 거?","JPN":"あの騎士の侵食体をマネてる奴らがいたってこと！","ENG":"There were those who were mimicking the C.O. knights!","TWN":"有人在模仿那些騎士侵蝕體欸？"},"stage":{"bg":"MS_1104","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};